```cpp
#include <string>
#include <unordered_set>
#include <vector>

using namespace std;

vector<string> solve(string s) {
    unordered_set<string> seen;
    vector<string> segments;
    int start = 0;
    while (start < s.size()) {
        string current;
        int i = start;
        while (i < s.size()) {
            current += s[i];
            if (seen.find(current) == seen.end()) {
                seen.insert(current);
                segments.push_back(current);
                start = i + 1;
                break;
            } else {
                i++;
            }
        }
    }
    return segments;
}
```

