那现在，编写代码。根据上面的思路，代码如下：

在C++中，需要包含头文件：

#include <string>
#include <unordered_set>
#include <vector>

然后，函数的定义：

vector<string> solve(string s) {
    unordered_set<string> seen;
    vector<string> segments;
    int start = 0;
    while (start < s.size()) {
        string current;
        int i = start;
        while (i < s.size()) {
            current += s[i];
            if (seen.find(current) == seen.end()) {
                seen.insert(current);
                segments.push_back(current);
                start = i + 1;
                break;
            }
            i++;
        }
    }
    return segments;
}

